  var x := (lx + rx) / 2;
  r := y + 1;
  c := x + 1;

  assert r == y + 1;
  assert y == gcr;
  assert lx + rx == 2 * gcc + 1;
  assert x == gcc;
  assert c == x + 1;
  assert r == gcr + 1;
  assert c == gcc + 1;
