      assert grid[ly][rx] == 'B';
      assert rx == gcc + ghalf + 1;
    }
    rx := rx + 1;
  }
  if rx <= gcc + ghalf {
    assert rx == gcc + ghalf;
    assert grid[ly][rx] == 'B';
    assert rx == gcc + ghalf;
  }
  assert rx == gcc + ghalf + 1;

