  var rx := lx + 1;
  while rx < |grid[ly]| && grid[ly][rx] == 'B'
    invariant gcc - ghalf < rx <= gcc + ghalf + 1
    decreases gcc + ghalf + 1 - rx
  {
    if rx > gcc + ghalf {
      assert rx > gcc + ghalf;
      assert rx > gcc + ghalf;
      assert rx > gcc + ghalf;
    }
    rx := rx + 1;
  }
  if rx <= gcc + ghalf {
    assert rx == gcc + ghalf;
    assert rx == gcc + ghalf;
    assert rx == gcc + ghalf;
  }
  assert rx == gcc + ghalf + 1;

  // Compute center
  var y := (ly + ry) / 2;
  var x := (lx + rx) / 2;
  r := y + 1;
  c := x + 1;

  assert y == gcr;
  assert y == gcr;
  assert lx + rx == 2 * gcc + 1;
  assert x == gcc;
  assert x == gcc;
  assert y == gcr;
  assert r == gcr + 1;
  assert c == gcc + 1;
  assert r == gcr + 1 && c == gcc + 1;
  ProveExistsH(n, m, grid, r - 1, c - 1, ghalf);
